/** Whether the toolbar is expanded */
isExpanded = signal(false);

/** Whether the editor textarea is focused */
editorFocused = input(false);

/** Track whether the user has manually toggled the toolbar */
private manuallyCollapsed = false;

constructor() {
  // Restore state from localStorage
  const saved = localStorage.getItem(STORAGE_KEYS.EDITOR_EXPANDED);
  if (saved !== null) {
    this.isExpanded.set(saved === 'true');
  }

  // Auto-save state changes
  effect(() => {
    localStorage.setItem(STORAGE_KEYS.EDITOR_EXPANDED, String(this.isExpanded()));
  });

  // Auto-expand when editor gets focus (unless user manually collapsed)
  effect(() => {
    if (this.editorFocused() && !this.isExpanded() && !this.manuallyCollapsed) {
      this.isExpanded.set(true);
    }
  });
}

/** Toggle toolbar visibility */
toggleToolbar() {
  const next = !this.isExpanded();
  this.isExpanded.set(next);
  // If user manually collapses, don't auto-expand on next focus
  this.manuallyCollapsed = !next;
}

