  const savedDraft = localStorage.getItem(STORAGE_KEYS.DRAFT_CONTENT);
  const savedImages = localStorage.getItem(STORAGE_KEYS.DRAFT_IMAGES);

  if (savedDraft) {
    // Restore image store if available
    if (savedImages) {
      this.imageStore.deserialize(savedImages);
    }

    // Legacy migration: draft contains inline base64 but no separate image store
    if (!savedImages) {
      const migrated = this.imageStore.internalize(savedDraft);
      this.markdownInput.set(migrated);
      this.initialContent.set(migrated);
    } else {
      this.markdownInput.set(savedDraft);
      this.initialContent.set(savedDraft);
    }

    this.contentLoaded.set(true);
    this.toast.show(this.i18n.dict()['msg.draft_restored']);
    // Still load feature.md in background for the "restore guide" feature
    this.http.get('./assets/feature.md', { responseType: 'text' }).subscribe({
      next: (text) => this.defaultGuideContent.set(text),
      error: () => {} // Keep DEFAULT_CONTENT fallback
    });
    return;
  }

  // No draft — load feature.md as default content
  this.http.get('./assets/feature.md', { responseType: 'text' }).subscribe({
    next: (text) => {
       this.markdownInput.set(text);
       this.defaultGuideContent.set(text);
       this.initialContent.set(text);
       this.contentLoaded.set(true);
    },
    error: (err) => {
      console.warn('Failed to load assets/feature.md. Using fallback content.', err);
      this.markdownInput.set(DEFAULT_CONTENT);
      this.defaultGuideContent.set(DEFAULT_CONTENT);
      this.initialContent.set(DEFAULT_CONTENT);
      this.contentLoaded.set(true);
    }
  });
}

