openAboutModal() {
   this.isAboutModalOpen.set(true);
   // Lazy-load feature.md for the About modal (only on first open)
   if (this.defaultGuideContent() === DEFAULT_CONTENT) {
     this.http.get('./assets/feature.md', { responseType: 'text' }).subscribe({
       next: (text) => this.defaultGuideContent.set(text),
       error: () => {} // Keep DEFAULT_CONTENT as fallback
     });
   }
}
